#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long d,x,y,z; scanf("%lld %lld %lld %lld", &d, &x, &y, &z);
        long long total1 = 7LL * x;
        long long total2 = d * y + (7LL - d) * z;
        long long ans = total1 > total2 ? total1 : total2;
        printf("%lld\n", ans);
    }
    return 0;
}

